  1→import { createContext, useContext, useState, useEffect, useCallback, useRef, ReactNode } from 'react'
  2→import { apiClient, ProjectInvitation, AppNotification } from '../lib/api'
  3→
  4→interface NotificationContextType {
  5→  count: number
  6→  invitations: ProjectInvitation[]
  7→  notifications: AppNotification[]
  8→  unreadNotifCount: number
  9→  refreshInvitations: () => Promise<void>
 10→  refreshNotifications: () => Promise<void>
 11→  acceptInvitation: (id: number) => Promise<void>
 12→  rejectInvitation: (id: number) => Promise<void>
 13→  markNotificationRead: (id: number) => Promise<void>
 14→  markAllNotificationsRead: () => Promise<void>
 15→}
 16→
 17→const NotificationContext = createContext<NotificationContextType | undefined>(undefined)
 18→
 19→// Derive WebSocket base URL from the same logic as API_BASE_URL
 20→function getWSBase(): string {
 21→  const apiBase = (import.meta.env.VITE_API_URL as string | undefined) ||
 22→    (import.meta.env.PROD ? '' : 'http://localhost:8080')
 23→  if (!apiBase) {
 24→    const proto = window.location.protocol === 'https:' ? 'wss:' : 'ws:'
 25→    return `${proto}//${window.location.host}`
 26→  }
 27→  return apiBase.replace(/^http/, 'ws')
 28→}
 29→
 30→export function NotificationProvider({ children }: { children: ReactNode }) {
 31→  const [invitations, setInvitations] = useState<ProjectInvitation[]>([])
 32→  const [notifications, setNotifications] = useState<AppNotification[]>([])
 33→  const mountedRef = useRef(true)
 34→
 35→  const refreshInvitations = useCallback(async () => {
 36→    try {
 37→      const data = await apiClient.getMyProjectInvitations()
 38→      if (mountedRef.current) {
 39→        setInvitations(data.filter(inv => inv.status === 'pending'))
 40→      }
 41→    } catch {
 42→      // ignore — will retry on next poll or WS event
 43→    }
 44→  }, [])
 45→
 46→  const refreshNotifications = useCallback(async () => {
 47→    try {
 48→      const data = await apiClient.getNotifications()
 49→      if (mountedRef.current) {
 50→        setNotifications(data)
 51→      }
 52→    } catch {
 53→      // ignore
 54→    }
 55→  }, [])
 56→
 57→  // WebSocket connection with reconnect
 58→  useEffect(() => {
 59→    mountedRef.current = true
 60→    let ws: WebSocket | null = null
 61→    let reconnectTimer: ReturnType<typeof setTimeout> | null = null
 62→    let delay = 1000
 63→
 64→    const connect = () => {
 65→      if (!mountedRef.current) return
 66→      const token = localStorage.getItem('auth_token')
 67→      if (!token) return
 68→
 69→      ws = new WebSocket(`${getWSBase()}/api/ws/user?token=${encodeURIComponent(token)}`)
 70→
 71→      ws.onopen = () => {
 72→        delay = 1000
 73→      }
 74→
 75→      ws.onmessage = (event) => {
 76→        try {
 77→          const msg = JSON.parse(event.data as string) as { type: string; payload?: unknown }
 78→          if (msg.type === 'project_invitation') {
 79→            refreshInvitations()
 80→          } else if (msg.type === 'project_membership') {
 81→            window.dispatchEvent(new CustomEvent('project-membership-changed'))
 82→            refreshInvitations()
 83→          } else if (msg.type === 'task_created' || msg.type === 'task_updated' || msg.type === 'task_deleted') {
 84→            window.dispatchEvent(new CustomEvent(msg.type, { detail: msg.payload }))
 85→          } else if (msg.type === 'notification') {
 86→            refreshNotifications()
 87→          }
 88→        } catch {
 89→          // ignore malformed messages
 90→        }
 91→      }
 92→
 93→      ws.onclose = () => {
 94→        ws = null
 95→        if (!mountedRef.current) return
 96→        reconnectTimer = setTimeout(() => {
 97→          delay = Math.min(delay * 2, 30000)
 98→          connect()
 99→        }, delay)
100→      }
101→
102→      ws.onerror = () => {
103→        ws?.close()
104→      }
105→    }
106→
107→    refreshInvitations()
108→    refreshNotifications()
109→    connect()
110→
111→    // Polling fallback every 60s
112→    const pollInterval = setInterval(() => {
113→      refreshInvitations()
114→      refreshNotifications()
115→    }, 60_000)
116→
117→    return () => {
118→      mountedRef.current = false
119→      clearInterval(pollInterval)
120→      if (reconnectTimer) clearTimeout(reconnectTimer)
121→      if (ws) {
122→        ws.onclose = null
123→        ws.close()
124→      }
125→    }
126→  }, [refreshInvitations, refreshNotifications])
127→
128→  const acceptInvitation = useCallback(async (id: number) => {
129→    await apiClient.acceptProjectInvitation(id)
130→    window.dispatchEvent(new CustomEvent('project-membership-changed'))
131→    await refreshInvitations()
132→  }, [refreshInvitations])
133→
134→  const rejectInvitation = useCallback(async (id: number) => {
135→    await apiClient.rejectProjectInvitation(id)
136→    await refreshInvitations()
137→  }, [refreshInvitations])
138→
139→  const markNotificationRead = useCallback(async (id: number) => {
140→    await apiClient.markNotificationsRead([id])
141→    if (mountedRef.current) {
142→      setNotifications(prev => prev.map(n => n.id === id ? { ...n, read_at: new Date().toISOString() } : n))
143→    }
144→  }, [])
145→
146→  const markAllNotificationsRead = useCallback(async () => {
147→    await apiClient.markAllNotificationsRead()
148→    if (mountedRef.current) {
149→      setNotifications(prev => prev.map(n => ({ ...n, read_at: n.read_at ?? new Date().toISOString() })))
150→    }
151→  }, [])
152→
153→  const unreadNotifCount = notifications.filter(n => !n.read_at).length
154→
155→  return (
156→    <NotificationContext.Provider value={{
157→      count: invitations.length + unreadNotifCount,
158→      invitations,
159→      notifications,
160→      unreadNotifCount,
161→      refreshInvitations,
162→      refreshNotifications,
163→      acceptInvitation,
164→      rejectInvitation,
165→      markNotificationRead,
166→      markAllNotificationsRead,
167→    }}>
168→      {children}
169→    </NotificationContext.Provider>
170→  )
171→}
172→
173→// eslint-disable-next-line react-refresh/only-export-components
174→export function useNotifications() {
175→  const context = useContext(NotificationContext)
176→  if (!context) throw new Error('useNotifications must be used within NotificationProvider')
177→  return context
178→}
